  tools.exec_command({cmd:"find . -maxdepth 2 -type f \\( -name 'HANDOFF.md' -o -name '*S02*' -o -name '*s02*' -o -name 'README*' \\) -print | sort",workdir:pack,yield_time_ms:10000,max_output_tokens:12000})
]);
text("STATE\n"+a.output+"\nTASKPACK_FILES\n"+b.output+"\nTARGET_FILES\n"+c.output);

const repo="[REDACTED_LOCAL_PATH]";
const script=`require "json"
rows=STDIN.read.split("\\0").filter_map do |r|
  m=r.match(/\\A\\d+ \\w+ [0-9a-f]+\\s+(-|\\d+)\\t(.*)\\z/m)
  next unless m && m[1] != "-"
  [m[2], m[1].to_i]
end
rawp=->(p){ p.match?(%r{(^|/)(raw|session_history)(/|$)}i) }
top=Hash.new{|h,k|h[k]=[0,0]}
ext=Hash.new{|h,k|h[k]=[0,0]}
rows.each do |p,s|
  key=p.include?("/") ? p.split("/",2)[0] : "(root)"
  top[key][0]+=1; top[key][1]+=s
  e=File.extname(p).downcase; e="(none)" if e.empty?
  ext[e][0]+=1; ext[e][1]+=s
end
raw=rows.select{|p,s|rawp[p]}
non=rows.reject{|p,s|rawp[p]}
docs=non.select{|p,s|p.downcase.end_with?(".md")}
agents=non.select{|p,s|File.basename(p).casecmp("AGENTS.md")==0}
packages=non.select{|p,s|File.basename(p)=="package.json"}
scripts=non.select{|p,s|p.match?(%r{(^|/)(scripts?|bin|tools?)/}) && p.match?(/\\.(py|sh|bash|zsh|js|mjs|cjs|ts|tsx)$/i)}
out={
  snapshot_files: rows.length,
  snapshot_bytes: rows.sum{|_,s|s},
  raw_or_session_history_files: raw.length,
  raw_or_session_history_bytes: raw.sum{|_,s|s},
  nonraw_files: non.length,
  nonraw_bytes: non.sum{|_,s|s},
  nonraw_markdown_files: docs.length,
  nonraw_markdown_bytes: docs.sum{|_,s|s},
  agents_files: agents.length,
  agents_bytes: agents.sum{|_,s|s},
  package_json_files: packages.length,
  package_json_bytes: packages.sum{|_,s|s},
  script_dir_source_files: scripts.length,
  script_dir_source_bytes: scripts.sum{|_,s|s},
  top_level: top.sort_by{|k,v|-v[1]}.to_h,
  extensions_top20: ext.sort_by{|k,v|-v[1]}.first(20).to_h
}
puts JSON.pretty_generate(out)`;
const largest=`git ls-tree -r -l -z origin/main | ruby -0 -ne 'm=$_.match(/\\A\\d+ \\w+ [0-9a-f]+\\s+(\\d+)\\t(.*)\\z/m); next unless m; p=m[2]; next if p.match?(%r{(^|/)(raw|session_history)(/|$)}i); puts sprintf(\"%10d\\t%s\",m[1].to_i,p)' | sort -nr | head -n 80`;
