abort "ls-tree failed" unless tree_status.success?
rows = tree.split("\\0").filter_map do |r|
  m = r.match(/\\A\\d+ blob ([0-9a-f]+)\\t(.*)\\z/m)
  m && {sha: m[1], path: m[2]}
end
unique = rows.map { |r| r[:sha] }.uniq
batch_in = unique.join("\\n") + "\\n"
out, err, status = Open3.capture3({"GIT_NO_LAZY_FETCH"=>"1"}, "git", "-c", "gc.auto=0", "cat-file", "--batch-check=%(objectname) %(objecttype) %(objectsize)", stdin_data: batch_in)
warn err unless err.empty?
size = {}
missing = []
out.each_line do |line|
  parts = line.split
  if parts[1] == "blob"
    size[parts[0]] = parts[2].to_i
  else
    missing << parts[0]
  end
end
rows.each { |r| r[:size] = size[r[:sha]] }
rawp = ->(p) { p.match?(%r{(^|/)(raw|session_history)(/|$)}i) }
present = rows.select { |r| r[:size] }
raw = present.select { |r| rawp[r[:path]] }
non = present.reject { |r| rawp[r[:path]] }
sum = ->(xs) { xs.sum { |r| r[:size] } }
puts "COVERAGE"
puts ["tree_blobs", rows.length].join("\\t")
