ag = non.select { |r| File.basename(r[:path]).downcase == "agents.md" }
pkg = non.select { |r| File.basename(r[:path]) == "package.json" }
scripts = non.select { |r| r[:path].match?(%r{(^|/)(scripts?|bin|tools?)/}) && r[:path].match?(/\\.(py|sh|bash|zsh|js|mjs|cjs|ts|tsx)$/i) }
