puts "LARGEST_MD"
md.sort_by { |r| -r[:size] }.first(60).each { |r| puts [r[:size],r[:sha],r[:path]].join("\\t") }
puts "TARGET_ENTRIES"
non.select { |r| File.basename(r[:path]).match?(/\\A(App\\.(tsx|jsx|ts|js)|atlasctl\\.py|main\\.(py|ts|tsx|js|jsx))\\z/i) }.sort_by { |r| -r[:size] }.each { |r| puts [r[:size],r[:sha],r[:path]].join("\\t") }
puts "VALIDATOR_CANDIDATES"
vals = non.select { |r| r[:path].match?(/(validat(or|e|ion)|audit|quality[_-]?gate|preflight|doctor|check)/i) && r[:path].match?(/\\.(py|sh|js|mjs|cjs|ts|tsx)$/i) }
puts ["count", vals.length, sum[vals]].join("\\t")
vals.sort_by { |r| -r[:size] }.first(120).each { |r| puts [r[:size],r[:sha],r[:path]].join("\\t") }
puts "VALIDATOR_EXACT_DUPLICATE_BLOBS"
vals.group_by { |r| r[:sha] }.select { |_,xs| xs.length > 1 }.sort_by { |_,xs| -xs.length }.each do |sha,xs|
  puts ["GROUP",sha,xs.length,xs.first[:size]].join("\\t")
  xs.each { |r| puts ["PATH",r[:path]].join("\\t") }
end
puts "PACKAGE_PATHS"
pkg.sort_by { |r| r[:path] }.each { |r| puts [r[:size],r[:sha],r[:path]].join("\\t") }
puts "SCRIPT_FAMILY_COUNTS"
patterns = {
  "validate" => /validat/i,
  "audit" => /audit/i,
  "check" => /check/i,
  "preflight" => /preflight/i,
  "stage_or_version" => /(^|[_.-])(stage|s\\d{2,}|v\\d+)[_.-]/i,
  "migration" => /migrat/i,
  "backfill" => /backfill/i,
  "install" => /install/i,
  "sync" => /sync/i,
  "deploy" => /deploy/i
}
patterns.each do |name,pat|
  xs=scripts.select { |r| File.basename(r[:path]).match?(pat) }
  puts [name,xs.length,sum[xs]].join("\\t")
end
puts "LARGEST_SCRIPTS"
scripts.sort_by { |r| -r[:size] }.first(100).each { |r| puts [r[:size],r[:sha],r[:path]].join("\\t") }
RUBY`;
